def merge_ranges(pairs):
    result = sorted(pairs, key=lambda x: x[0])
    merged = [result[0]]

    for pair in result[1:]:
        last_range = merged[-1]
        if last_range[1] >= pair[0]:
            last_range[1] = max(last_range[1], pair[1])
        else:
            merged.append(pair)

